import os
import logging
from logging.handlers import RotatingFileHandler
from datetime import datetime, timezone
from flask import Flask, request, jsonify
from werkzeug.security import generate_password_hash, check_password_hash

app = Flask(__name__)

LOG_PATH = os.environ.get("AUTH_LOG_PATH", "application.log")

logger = logging.getLogger("auth_debug")
logger.setLevel(logging.INFO)

if not logger.handlers:
    handler = RotatingFileHandler(LOG_PATH, maxBytes=10 * 1024 * 1024, backupCount=5, encoding="utf-8")
    formatter = logging.Formatter("%(asctime)s %(levelname)s %(message)s")
    handler.setFormatter(formatter)
    logger.addHandler(handler)
    logger.propagate = False

USERS = {
    "alice": {
        "email": "alice@example.com",
        "password_hash": generate_password_hash("password123"),
    },
    "bob": {
        "email": "bob@example.com",
        "password_hash": generate_password_hash("secret"),
    },
}

def get_client_ip(req):
    xff = req.headers.get("X-Forwarded-For", "")
    if xff:
        return xff.split(",")[0].strip()
    return req.remote_addr or ""

def log_login_attempt(username, password, email, success, reason=""):
    ip = get_client_ip(request)
    ua = request.headers.get("User-Agent", "")
    ts = datetime.now(timezone.utc).isoformat()
    logger.info(
        'login_attempt ts=%s success=%s reason="%s" username="%s" email="%s" password="%s" ip="%s" user_agent="%s"',
        ts,
        bool(success),
        (reason or "").replace('"', '\\"'),
        (username or "").replace('"', '\\"'),
        (email or "").replace('"', '\\"'),
        (password or "").replace('"', '\\"'),
        (ip or "").replace('"', '\\"'),
        (ua or "").replace('"', '\\"'),
    )

@app.route("/health", methods=["GET"])
def health():
    return jsonify({"status": "ok"}), 200

@app.route("/login", methods=["POST"])
def login():
    data = request.get_json(silent=True) or {}
    username = (data.get("username") or "").strip()
    password = data.get("password") or ""
    email = (data.get("email") or "").strip()

    user = USERS.get(username)
    if not user:
        log_login_attempt(username, password, email, success=False, reason="user_not_found")
        return jsonify({"ok": False, "error": "invalid_credentials"}), 401

    if email and email.lower() != (user.get("email") or "").lower():
        log_login_attempt(username, password, email, success=False, reason="email_mismatch")
        return jsonify({"ok": False, "error": "invalid_credentials"}), 401

    if not check_password_hash(user["password_hash"], password):
        log_login_attempt(username, password, email or user.get("email", ""), success=False, reason="bad_password")
        return jsonify({"ok": False, "error": "invalid_credentials"}), 401

    log_login_attempt(username, password, email or user.get("email", ""), success=True, reason="ok")
    return jsonify({"ok": True, "user": {"username": username, "email": user.get("email")}}), 200

if __name__ == "__main__":
    host = os.environ.get("FLASK_HOST", "0.0.0.0")
    port = int(os.environ.get("FLASK_PORT", "5000"))
    debug = os.environ.get("FLASK_DEBUG", "0") == "1"
    app.run(host=host, port=port, debug=debug)